    return res.status(401).json({ message: 'Authentication token missing or malformed.' });
  }

  const token = authHeader.split(' ')[1];

  try {
    // Verify token using your JWT secret from environment variables
    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    req.user = decoded; // Attach user payload to request
    next(); // Proceed to the next middleware/route handler
  } catch (error) {
    if (error.name === 'TokenExpiredError') {
      return res.status(401).json({ message: 'Authentication token expired. Please log in again.' });
    } else if (error.name === 'JsonWebTokenError') {
      return res.status(401).json({ message: 'Invalid authentication token. Access denied.' });
    } else {
      // Catch other potential errors during verification
      return res.status(401).json({ message: 'Authentication failed. Unexpected error.' });
    }
  }
};

