// server/src/middleware/auth.ts (Example Express.js Auth Middleware)
import { Request, Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';

interface AuthenticatedRequest extends Request {
  user?: any; // Extend Request type to include 'user' property after authentication
}

export const authenticateToken = (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1]; // Expects 'Bearer TOKEN'

  if (token == null) {
    console.log('Auth Middleware: No token provided, returning 401.');
    return res.status(401).json({ message: 'Authentication token required' });
  }

  const jwtSecret = process.env.JWT_SECRET;
  if (!jwtSecret) {
    console.error('Auth Middleware: JWT_SECRET is not defined in environment variables. Critical configuration missing.');
    return res.status(500).json({ message: 'Server configuration error: JWT secret missing' });
  }

  jwt.verify(token, jwtSecret, (err: any, user: any) => {
    if (err) {
      console.log('Auth Middleware: Token verification failed:', err.message, 'Returning 401.');
      // Log specific error details from 'err' for debugging (e.g., TokenExpiredError, JsonWebTokenError)
      return res.status(401).json({ message: 'Invalid or expired authentication token' });
    }
    req.user = user; // Attach decoded user payload to the request object
    next();
  });
};
